// 排版页眉页脚：小五号字体，页码居中阿拉伯数字，页眉线单细线
var doc = Application.ActiveDocument;
var sections = doc.Sections;
var results = [];

for (var i = 1; i <= sections.Count; i++) {
    var section = sections.Item(i);

    // 设置页眉
    var header = section.Headers.Item(1); // wdHeaderFooterPrimary = 1
    var headerRange = header.Range;
    headerRange.Font.Size = 9; // 小五号 = 9磅
    headerRange.Font.Name = "宋体";

    // 添加页眉线（单细线）
    var headerBorders = header.Borders.Item(2); // wdBorderBottom = 2
    headerBorders.LineStyle = 1; // wdLineStyleSingle = 1
    headerBorders.LineWidth = 0; // wdLineWidth050pt = 0 (0.5磅细线)
    headerBorders.Color = 0; // 黑色

    // 设置页脚
    var footer = section.Footers.Item(1); // wdHeaderFooterPrimary = 1
    var footerRange = footer.Range;
    footerRange.Font.Size = 9; // 小五号 = 9磅
    footerRange.Font.Name = "宋体";
    footerRange.ParagraphFormat.Alignment = 1; // wdAlignParagraphCenter = 1 居中

    // 插入页码（阿拉伯数字，居中）
    var pageNumbers = footer.PageNumbers;
    pageNumbers.Add(1, 1); // wdPageNumberPositionBottom = 1, wdAlignPageNumberCenter = 1
    pageNumbers.NumberStyle = 0; // wdPageNumberStyleArabic = 0 阿拉伯数字

    results.push("第" + i + "节页眉页脚已设置");
}

return "完成：" + results.join("；");

